import os
import hashlib
import json
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import joblib
import numpy as np
from datetime import datetime
import uuid

app = Flask(__name__)

# Configuration
UPLOAD_FOLDER = 'models'
ALLOWED_EXTENSIONS = {'joblib', 'pkl'}
MAX_FILE_SIZE = 100 * 1024 * 1024  # 100MB
MODEL_METADATA_FILE = 'model_metadata.json'

os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Store model metadata
model_registry = {}

def load_model_metadata():
    global model_registry
    if os.path.exists(MODEL_METADATA_FILE):
        with open(MODEL_METADATA_FILE, 'r') as f:
            model_registry = json.load(f)

def save_model_metadata():
    with open(MODEL_METADATA_FILE, 'w') as f:
        json.dump(model_registry, f, indent=2)

load_model_metadata()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def compute_file_hash(filepath):
    sha256_hash = hashlib.sha256()
    with open(filepath, "rb") as f:
        for byte_block in iter(lambda: f.read(4096), b""):
            sha256_hash.update(byte_block)
    return sha256_hash.hexdigest()

def safe_load_model(filepath):
    """
    Safely load a model using joblib instead of pickle.
    Joblib is more secure and handles numpy arrays better.
    """
    try:
        # Use joblib which is safer than pickle for ML models
        model = joblib.load(filepath)
        return model, None
    except Exception as e:
        return None, str(e)

def validate_model(model):
    """
    Validate that the loaded object has expected ML model attributes.
    This adds an additional security layer.
    """
    # Check if model has common ML model methods
    required_methods = ['predict']
    
    for method in required_methods:
        if not hasattr(model, method):
            return False, f"Model missing required method: {method}"
    
    # Check if predict method is callable
    if not callable(getattr(model, 'predict', None)):
        return False, "predict method is not callable"
    
    return True, "Model validated successfully"

@app.route('/upload', methods=['POST'])
def upload_model():
    """
    Endpoint to upload custom models for inference.
    Uses secure deserialization with joblib and validation.
    """
    if 'model' not in request.files:
        return jsonify({'error': 'No model file provided'}), 400
    
    file = request.files['model']
    tenant_id = request.form.get('tenant_id', 'default')
    model_name = request.form.get('model_name', '')
    model_version = request.form.get('model_version', '1.0')
    
    if file.filename == '':
        return jsonify({'error': 'No selected file'}), 400
    
    if not allowed_file(file.filename):
        return jsonify({'error': 'File type not allowed. Use .joblib or .pkl files'}), 400
    
    if not model_name:
        return jsonify({'error': 'model_name is required'}), 400
    
    # Generate unique model ID
    model_id = str(uuid.uuid4())
    
    # Secure filename
    filename = secure_filename(file.filename)
    # Use joblib extension for consistency
    filename = f"{model_id}_{filename}"
    if not filename.endswith('.joblib'):
        filename = filename.rsplit('.', 1)[0] + '.joblib'
    
    filepath = os.path.join(UPLOAD_FOLDER, filename)
    
    # Save file temporarily
    file.save(filepath)
    
    # Check file size
    file_size = os.path.getsize(filepath)
    if file_size > MAX_FILE_SIZE:
        os.remove(filepath)
        return jsonify({'error': f'File size exceeds maximum allowed size of {MAX_FILE_SIZE} bytes'}), 400
    
    # Compute file hash for integrity
    file_hash = compute_file_hash(filepath)
    
    # Safely load and validate model
    model, error = safe_load_model(filepath)
    
    if error:
        os.remove(filepath)
        return jsonify({'error': f'Failed to load model: {error}'}), 400
    
    # Validate model structure
    is_valid, validation_message = validate_model(model)
    
    if not is_valid:
        os.remove(filepath)
        return jsonify({'error': f'Model validation failed: {validation_message}'}), 400
    
    # Store model metadata
    model_registry[model_id] = {
        'model_id': model_id,
        'tenant_id': tenant_id,
        'model_name': model_name,
        'model_version': model_version,
        'filename': filename,
        'filepath': filepath,
        'file_hash': file_hash,
        'file_size': file_size,
        'upload_timestamp': datetime.utcnow().isoformat(),
        'status': 'active'
    }
    
    save_model_metadata()
    
    return jsonify({
        'message': 'Model uploaded successfully',
        'model_id': model_id,
        'model_name': model_name,
        'model_version': model_version,
        'file_hash': file_hash
    }), 201

@app.route('/predict/<model_id>', methods=['POST'])
def predict(model_id):
    """
    Endpoint to perform inference using uploaded model.
    """
    if model_id not in model_registry:
        return jsonify({'error': 'Model not found'}), 404
    
    model_info = model_registry[model_id]
    
    if model_info['status'] != 'active':
        return jsonify({'error': 'Model is not active'}), 400
    
    # Verify tenant access (simplified - in production use proper auth)
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if model_info['tenant_id'] != tenant_id:
        return jsonify({'error': 'Unauthorized access to model'}), 403
    
    # Get input data
    data = request.get_json()
    if not data or 'input' not in data:
        return jsonify({'error': 'No input data provided'}), 400
    
    try:
        input_data = np.array(data['input'])
    except Exception as e:
        return jsonify({'error': f'Invalid input format: {str(e)}'}), 400
    
    # Load model securely
    model, error = safe_load_model(model_info['filepath'])
    
    if error:
        return jsonify({'error': f'Failed to load model: {error}'}), 500
    
    # Perform prediction
    try:
        prediction = model.predict(input_data)
        
        # Convert numpy types to Python native types for JSON serialization
        if isinstance(prediction, np.ndarray):
            prediction = prediction.tolist()
        
        return jsonify({
            'model_id': model_id,
            'model_name': model_info['model_name'],
            'prediction': prediction
        }), 200
    
    except Exception as e:
        return jsonify({'error': f'Prediction failed: {str(e)}'}), 500

@app.route('/models', methods=['GET'])
def list_models():
    """
    List all models for a tenant.
    """
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    
    tenant_models = [
        {
            'model_id': model_id,
            'model_name': info['model_name'],
            'model_version': info['model_version'],
            'upload_timestamp': info['upload_timestamp'],
            'status': info['status']
        }
        for model_id, info in model_registry.items()
        if info['tenant_id'] == tenant_id
    ]
    
    return jsonify({'models': tenant_models}), 200

@app.route('/models/<model_id>', methods=['DELETE'])
def delete_model(model_id):
    """
    Delete a model.
    """
    if model_id not in model_registry:
        return jsonify({'error': 'Model not found'}), 404
    
    model_info = model_registry[model_id]
    
    # Verify tenant access
    tenant_id = request.headers.get('X-Tenant-ID', 'default')
    if model_info['tenant_id'] != tenant_id:
        return jsonify({'error': 'Unauthorized access to model'}), 403
    
    # Delete file
    if os.path.exists(model_info['filepath']):
        os.remove(model_info['filepath'])
    
    # Remove from registry
    del model_registry[model_id]
    save_model_metadata()
    
    return jsonify({'message': 'Model deleted successfully'}), 200

